#include <stdio.h>
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        long long A[N], dp[N + 1][M + 1] = {{1}};
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= M; j++) {
                dp[i][j] = dp[i - 1][j] * A[i - 1];
            }
        }
        printf("%lld\n", dp[N][M]);
    }
    return 0;
}

