    input.push(line);
}).on('close', function() {
    let T = parseInt(input.shift());
    for (let i = 0; i < T; i++) {
        let [N, M] = input.shift().split(' ').map(Number);
        let A = input.shift().split(' ').map(Number);
        let dp = Array(N + 1).fill(0).map(() => Array(M + 1).fill(1));
        for (let j = 1; j <= N; j++) {
            for (let k = 1; k <= M; k++) {
                dp[j][k] = dp[j - 1][k] * A[j - 1];
            }
        }
        console.log(dp[N][M]);
    }
});

